<?php
declare(strict_types=1);
namespace App\Services;
use App\Config\Database;use App\Http\HttpException;use App\Repositories\ActivityLogRepository;use App\Repositories\ProductRepository;use App\Repositories\PurchaseItemRepository;use App\Repositories\PurchaseRepository;use App\Repositories\PurchaseReturnRepository;use App\Repositories\StockTransactionRepository;use App\Repositories\SupplierRepository;use App\Validators\PurchaseReturnValidator;use Throwable;
final class PurchaseReturnService{
 public function __construct(private readonly Database$db,private readonly PurchaseRepository$purchases,private readonly PurchaseItemRepository$items,private readonly PurchaseReturnRepository$returns,private readonly SupplierRepository$suppliers,private readonly ProductRepository$products,private readonly StockTransactionRepository$stock,private readonly PurchaseReturnValidator$validator,private readonly ActivityLogRepository$activity){}
 public function list(array$q):array{return$this->returns->list($q);}public function get(int$id):array{$r=$this->returns->find($id);if(!$r)throw new HttpException('Purchase return not found.',404);return$r;}
 public function create(array$input,int$user):array{$d=$this->validator->data($input);$pdo=$this->db->connection();$pdo->beginTransaction();try{$purchase=$this->purchases->find($d['purchase_id'],true);if(!$purchase)throw new HttpException('Purchase not found.',404);if(!in_array($purchase['purchase_status'],['completed','partially_returned'],true))throw new HttpException('This purchase is not returnable.',409);$available=$this->items->returnable($d['purchase_id']);$lines=[];$subtotal=0;foreach($d['items']as$itemId=>$requested){$item=$available[$itemId]??null;if(!$item)throw new HttpException('A selected purchase item is unavailable.',409);$purchased=$this->scaled($item['quantity'],3);$returned=$this->scaled($item['returned_quantity'],3);$remaining=$purchased-$returned;$qty=$requested['quantity_milli'];if($qty>$remaining)throw new HttpException('Return quantity for '.$item['product_name'].' exceeds the remaining returnable quantity.',422);$current=$this->scaled($item['current_stock'],3);if((int)$item['track_stock']===1&&(int)$item['stock_posted']===1&&$current<$qty)throw new HttpException($item['product_name'].' only has '.$this->quantity($current).' available for return.',409);$originalLine=$this->scaled($item['line_total'],2);$line=(int)round($originalLine*$qty/$purchased);$subtotal+=$line;$lines[]=['item'=>$item,'quantity'=>$qty,'line'=>$line,'current'=>$current];}if($d['refund_cents']>$subtotal)throw new HttpException('Supplier refund cannot exceed the returned value.',422,['refund_amount'=>['Maximum refund is '.$this->money($subtotal).'.']]);$adjustment=-$subtotal+$d['refund_cents'];$number=$this->purchases->nextNumber($d['return_date'],true);$returnId=$this->returns->create(['return_number'=>$number,'purchase_id'=>$d['purchase_id'],'supplier_id'=>$purchase['supplier_id'],'return_date'=>$d['return_date'],'subtotal'=>$this->money($subtotal),'refund_amount'=>$this->money($d['refund_cents']),'balance_adjustment'=>$this->signedMoney($adjustment),'reason'=>$d['reason'],'processed_by'=>$user]);foreach($lines as$line){$item=$line['item'];$this->returns->addItem($returnId,['purchase_item_id'=>$item['id'],'product_id'=>$item['product_id'],'unit_id'=>$item['unit_id'],'unit_name_snapshot'=>$item['unit_name_snapshot'],'unit_symbol_snapshot'=>$item['unit_symbol_snapshot'],'quantity_entered'=>$this->quantity((int)round($line['quantity']/(float)$item['conversion_to_base_snapshot'])),'conversion_to_base_snapshot'=>$item['conversion_to_base_snapshot'],'quantity_base'=>$this->quantity($line['quantity']),'unit_cost'=>$item['unit_cost'],'line_total'=>$this->money($line['line'])]);$this->items->addReturned((int)$item['id'],$this->quantity($line['quantity']));if((int)$item['track_stock']===1&&(int)$item['stock_posted']===1){$new=$line['current']-$line['quantity'];$this->products->updateQuantity((int)$item['product_id'],$this->quantity($new));$this->stock->create(['product_id'=>$item['product_id'],'user_id'=>$user,'transaction_type'=>'purchase_return','quantity'=>$this->quantity($line['quantity']),'previous_stock'=>$this->quantity($line['current']),'new_stock'=>$this->quantity($new),'reason'=>'Purchase return '.$number,'reference_type'=>'purchase_return','reference_id'=>$returnId]);}}$this->suppliers->adjustBalance((int)$purchase['supplier_id'],$this->signedMoney($adjustment));$purchaseStatus=$this->items->remainingCount((int)$purchase['id'])===0?'returned':'partially_returned';$newDue=max(0,$this->scaled((string)$purchase['balance_due'],2)-$subtotal+$d['refund_cents']);$paymentStatus=$newDue===0?'paid':($this->scaled((string)$purchase['amount_paid'],2)>0?'partially_paid':'unpaid');$this->purchases->applyReturn((int)$purchase['id'],$purchaseStatus,$this->money($newDue),$paymentStatus);$this->activity->log($user,'purchase.returned','Purchase return '.$number.' completed.');$pdo->commit();return$this->get($returnId);}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}}
 private function scaled(string$v,int$s):int{[$w,$f]=array_pad(explode('.',$v,2),2,'');return(int)$w*(10**$s)+(int)str_pad(substr($f,0,$s),$s,'0');}private function money(int$c):string{return intdiv($c,100).'.'.str_pad((string)($c%100),2,'0',STR_PAD_LEFT);}private function signedMoney(int$c):string{return($c<0?'-':'').$this->money(abs($c));}private function quantity(int$m):string{return intdiv($m,1000).'.'.str_pad((string)($m%1000),3,'0',STR_PAD_LEFT);}
}
